"use client";

import { FormEvent, useMemo, useState } from "react";
import { useMutation, useQuery } from "convex/react";
import { api } from "../../convex/_generated/api";
import styles from "./page.module.css";

export default function Home() {
  const runId = useMemo(
    () => process.env.NEXT_PUBLIC_ZEALT_RUN_ID ?? "local",
    []
  );
  const [text, setText] = useState("");
  const tasks = useQuery(api.tasks.list, { runId }) ?? [];
  const addTask = useMutation(api.tasks.add);
  const toggleTask = useMutation(api.tasks.toggle);
  const removeTask = useMutation(api.tasks.remove);

  const handleSubmit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!text.trim()) {
      return;
    }
    await addTask({ text, runId });
    setText("");
  };

  return (
    <div className={styles.page}>
      <main className={styles.main}>
        <header className={styles.header}>
          <div>
            <h1>Task Manager</h1>
            <p>Run ID: {runId}</p>
          </div>
        </header>

        <form className={styles.form} onSubmit={handleSubmit}>
          <input
            className={styles.input}
            data-testid="task-input"
            type="text"
            placeholder="Add a task"
            value={text}
            onChange={(event) => setText(event.target.value)}
          />
          <button className={styles.addButton} data-testid="add-button" type="submit">
            Add Task
          </button>
        </form>

        <ul className={styles.list}>
          {tasks.length === 0 ? (
            <li className={styles.empty}>No tasks yet.</li>
          ) : (
            tasks.map((task) => (
              <li
                key={task._id}
                className={styles.task}
                data-testid="task-item"
              >
                <label className={styles.taskLabel}>
                  <input
                    data-testid="toggle-button"
                    type="checkbox"
                    checked={task.isCompleted}
                    onChange={() => toggleTask({ id: task._id, runId })}
                  />
                  <span
                    className={
                      task.isCompleted ? styles.completedText : styles.taskText
                    }
                  >
                    {task.text}
                  </span>
                </label>
                <button
                  className={styles.deleteButton}
                  data-testid="delete-button"
                  type="button"
                  onClick={() => removeTask({ id: task._id, runId })}
                >
                  Delete
                </button>
              </li>
            ))
          )}
        </ul>
      </main>
    </div>
  );
}

input.content:
.page {
  min-height: 100vh;
  background: #f5f6f8;
  color: #111827;
  display: flex;
  justify-content: center;
  padding: 48px 16px;
  font-family: var(--font-geist-sans);
}

.main {
  width: 100%;
  max-width: 640px;
  background: #ffffff;
  border-radius: 16px;
  box-shadow: 0 12px 30px rgba(15, 23, 42, 0.08);
  padding: 32px;
  display: flex;
  flex-direction: column;
  gap: 24px;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 16px;
}

.header h1 {
  margin: 0;
  font-size: 28px;
}

.header p {
  margin: 8px 0 0;
  color: #6b7280;
}

.form {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
}

.input {
  flex: 1;
  min-width: 220px;
  padding: 12px 14px;
  border-radius: 10px;
  border: 1px solid #d1d5db;
  font-size: 16px;
}

.addButton {
  border: none;
  background: #2563eb;
  color: #fff;
  padding: 12px 18px;
  border-radius: 10px;
  font-weight: 600;
  cursor: pointer;
}

.list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.task {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 12px 16px;
  border-radius: 12px;
  border: 1px solid #e5e7eb;
  background: #f9fafb;
}

.taskLabel {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 16px;
}

.taskText {
  color: #111827;
}

.completedText {
  color: #9ca3af;
  text-decoration: line-through;
}

.deleteButton {
  border: none;
  background: #ef4444;
  color: #fff;
  padding: 8px 12px;
  border-radius: 8px;
  cursor: pointer;
}

.empty {
  text-align: center;
  color: #6b7280;
  padding: 16px 0;
}

@media (max-width: 600px) {
  .main {
    padding: 24px;
  }

  .form {
    flex-direction: column;
  }

  .addButton {
    width: 100%;
  }
}
